import java.util.Arrays;

public double average(int[] salary) {
    double sum = 0;
    int minSalary = Arrays.stream(salary).min().getAsInt();
    int maxSalary = Arrays.stream(salary).max().getAsInt();
    for (int s : salary) {
        sum += s;
    }
    sum -= (minSalary + maxSalary);
    return sum / (salary.length - 2);
}
